/**
 * Benchmark the Prismatic Refraction fast path vs. the slow path.
 *
 * Fast path: `src/prismatic-refraction-fast.ts` — Uint8Array lanes,
 * two-pass count-then-fill, Math.imul content hash.
 *
 * Slow path: `src/prismatic-refraction.ts` — one `Shard` per byte,
 * `Array<number>` payloads, BigInt FNV-1a content hash.
 *
 * Reports MB/s per (payload, k) cell for `prism` (the single hot stage
 * the fast path optimizes) and emits an `ALL PASS` footer iff every
 * fast-path cell satisfies `lanesBounded && payloadPreserved`.
 *
 * Usage:
 *   cd open-source/gnosis
 *   node ./bin/gnode.js run scripts/benchmark-prismatic-refraction-fast.ts
 */

import {
  createRawStream,
  prism,
} from '../src/prismatic-refraction';
import {
  prismFast,
  wireToStorageFast,
  lanesBounded,
  payloadPreserved,
  type FastIngestContext,
} from '../src/prismatic-refraction-fast';

// ─── Seeded bytes ────────────────────────────────────────────────────

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s;
  };
}

function randomBytesTyped(seed: number, n: number): Uint8Array {
  const rng = lcg(seed);
  const out = new Uint8Array(n);
  for (let i = 0; i < n; i++) out[i] = rng() & 0xff;
  return out;
}

function randomBytesArray(seed: number, n: number): number[] {
  const rng = lcg(seed);
  const out = new Array<number>(n);
  for (let i = 0; i < n; i++) out[i] = rng() & 0xff;
  return out;
}

// ─── Timer ───────────────────────────────────────────────────────────

function bench<T>(
  iterations: number,
  fn: () => T,
): { meanMs: number; result: T } {
  // Warm-up.
  for (let i = 0; i < Math.max(3, Math.min(5, iterations)); i++) fn();
  const start = performance.now();
  let result: T = fn();
  for (let i = 1; i < iterations; i++) result = fn();
  const elapsed = performance.now() - start;
  return { meanMs: elapsed / iterations, result };
}

function mbPerSec(bytes: number, ms: number): number {
  return (bytes / ms) * 1000 / (1024 * 1024);
}

function fmtMB(mb: number): string {
  if (mb >= 100) return `${mb.toFixed(0)}`;
  if (mb >= 10) return `${mb.toFixed(1)}`;
  return `${mb.toFixed(2)}`;
}

function humanBytes(n: number): string {
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(0)} KB`;
  return `${(n / (1024 * 1024)).toFixed(0)} MB`;
}

// ─── Config ──────────────────────────────────────────────────────────

const PAYLOAD_SIZES = [
  1024,
  8 * 1024,
  64 * 1024,
  256 * 1024,
  1024 * 1024,
];

const LANE_COUNTS = [1, 4, 8, 16];

const CTX: FastIngestContext = {
  tenant: { hi: 7, lo: 11 },
  typeTag: 42,
  schemaKnotHash: 0xdeadbeef,
  provenanceDid: 0,
  freshnessClock: 0,
};

// ─── Header ──────────────────────────────────────────────────────────

console.log('# Prismatic Refraction Fast Path — Benchmark');
console.log('');
console.log(`Node ${process.versions.node} on ${process.platform}/${process.arch}.`);
console.log('');
console.log('Fast: `src/prismatic-refraction-fast.ts` (Uint8Array lanes, Math.imul hash).');
console.log('Slow: `src/prismatic-refraction.ts` (per-byte Shard, BigInt FNV-1a).');
console.log('');

// ─── Table: prism MB/s, slow vs fast ─────────────────────────────────

console.log('## prism — MB/s (higher is better)');
console.log('');
console.log('|         | k=1 slow | k=1 fast | k=4 slow | k=4 fast | k=8 slow | k=8 fast | k=16 slow | k=16 fast |');
console.log('|---------|---------:|---------:|---------:|---------:|---------:|---------:|----------:|----------:|');

let allPass = true;
let firstOneMbFastMB = 0;

for (const n of PAYLOAD_SIZES) {
  const slowStream = createRawStream(randomBytesArray(1, n));
  const fastBytes = randomBytesTyped(1, n);
  const iterations = Math.max(5, Math.floor(1_000_000 / n));
  const cells: string[] = [humanBytes(n).padStart(7, ' ')];

  for (const k of LANE_COUNTS) {
    const slow = bench(iterations, () => prism(slowStream, k));
    const fast = bench(iterations, () => prismFast(fastBytes, k));

    // Validate the fast path's lane outputs.
    const lanes = fast.result;
    const bounded = lanesBounded(lanes, k);
    const preserved = payloadPreserved(lanes, k, n);
    if (!bounded || !preserved) {
      allPass = false;
      console.error(
        `FAIL at n=${n} k=${k}: bounded=${bounded} preserved=${preserved}`,
      );
    }

    cells.push(fmtMB(mbPerSec(n, slow.meanMs)));
    cells.push(fmtMB(mbPerSec(n, fast.meanMs)));

    if (n === 1024 * 1024 && k === 1) {
      firstOneMbFastMB = mbPerSec(n, fast.meanMs);
    }
  }

  console.log(`| ${cells.join(' | ')} |`);
}

console.log('');

// ─── Table: wireToStorageFast end-to-end MB/s ────────────────────────

console.log('## wireToStorageFast — end-to-end MB/s (prism + per-lane block materialize)');
console.log('');
console.log('| Payload | k=1 | k=4 | k=8 | k=16 |');
console.log('|---------|----:|----:|----:|-----:|');

for (const n of PAYLOAD_SIZES) {
  const fastBytes = randomBytesTyped(2, n);
  const iterations = Math.max(5, Math.floor(1_000_000 / n));
  const cells: string[] = [humanBytes(n).padStart(7, ' ')];
  for (const k of LANE_COUNTS) {
    const { meanMs, result } = bench(iterations, () =>
      wireToStorageFast(fastBytes, k, CTX),
    );
    if (result.totalBytes !== n) {
      allPass = false;
      console.error(`FAIL totalBytes at n=${n} k=${k}: got ${result.totalBytes}`);
    }
    cells.push(fmtMB(mbPerSec(n, meanMs)));
  }
  console.log(`| ${cells.join(' | ')} |`);
}

console.log('');

// ─── Footer ──────────────────────────────────────────────────────────

if (allPass) {
  console.log('ALL PASS — every fast-path cell has `lanesBounded && payloadPreserved`.');
} else {
  console.log('FAILURES DETECTED — see FAIL lines above.');
  process.exit(1);
}

console.log('');
console.log(
  `1 MB / k=1 fast-path prism: ${fmtMB(firstOneMbFastMB)} MB/s (slow baseline ~25 MB/s).`,
);
